using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;

var build = BinaryLog.ReadBuild("/tmp/sv-42d4265faf1d40428c51ed91ddce3b02/build.binlog");
Console.WriteLine($"Build Succeeded: {build.Succeeded}");
Console.WriteLine();

// Find all errors
Console.WriteLine("=== ALL ERRORS ===");
build.VisitAllChildren<Error>(error => {
    Console.WriteLine($"[{error.ProjectFile}]");
    Console.WriteLine($"  {error.File}({error.LineNumber},{error.ColumnNumber}): error {error.Code}: {error.Text}");
    Console.WriteLine();
});

Console.WriteLine("=== ALL WARNINGS ===");
build.VisitAllChildren<Warning>(warning => {
    if (warning.Code?.StartsWith("CS") == true || warning.Code?.StartsWith("NU") == true)
    {
        Console.WriteLine($"[{warning.ProjectFile}] {warning.File}({warning.LineNumber}): warning {warning.Code}: {warning.Text}");
    }
});
EOF

